Here is an example code for a Discord bot using Discord.js v14 with one command "ban". The code is as follows:

```javascript
const Discord = require('discord.js');
const client = new Discord.Client();

const banCommand = {
  name: 'ban',
  category:'moderation',
  description: 'Bans a user from the server',
  options: [
    {
      name: 'user',
      description: 'The user to ban',
      type:'member'
    }
  ],
  run: async (message) => {
    const user = message.mentions.users.first();

    if (!user) {
      return message.reply('Please mention the user you want to ban.');
    }

    const member = message.guild.getMember(user.id);

    if (member) {
      await member.ban();
      message.reply(`Banned ${user.name} from the server.`);
    } else {
      message.reply('User not found.');
    }
  }
};

client.commands = new Discord.Collection();
client.commands.set(banCommand.name, banCommand);

client.on('ready', () => {
  console.log('Logged in as @' + client.user.tag + '!');
});

client.on('message', (message) => {
  if (message.content.startsWith(banCommand.name)) {
    message.deferReply(banCommand.run, []);
  }
});

client.login('YOUR_BOT_TOKEN');
```

Make sure to replace `YOUR_BOT_TOKEN` with your bot token from the Discord Developer Portal.

